@namespace Lumeo

<div role="@AriaRole" class="@CssClass" @attributes="AdditionalAttributes">
    <div class="flex flex-col items-center text-center">
        <div class="@IconContainerClasses">
            @if (IconContent is not null)
            {
                @IconContent
            }
            else
            {
                @DefaultIcon
            }
        </div>
        @if (!string.IsNullOrEmpty(Title))
        {
            <h3 class="@TitleClass">@Title</h3>
        }
        @if (!string.IsNullOrEmpty(SubTitle))
        {
            <p class="@SubTitleClass">@SubTitle</p>
        }
        @if (Extra is not null)
        {
            <div class="mt-6 flex items-center gap-2">
                @Extra
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public ResultStatus Status { get; set; } = ResultStatus.Info;
    // Status serves as this component's Variant — it drives color + icon. No duplicate Variant param needed.
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public string? Title { get; set; }
    [Parameter] public string? SubTitle { get; set; }

    /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    [Parameter] public RenderFragment? Extra { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Error-ish outcomes are assertive (role="alert") so AT interrupts; success/
    // info/not-found are polite (role="status"). A consumer role via attributes
    // still wins (splatted last). (#284)
    private string AriaRole => Status is ResultStatus.Error or ResultStatus.Forbidden or ResultStatus.ServerError
        ? "alert"
        : "status";

    private string CssClass => Cx.Merge(SizePaddingClass, "px-6", Class);

    private string SizePaddingClass => Size switch
    {
        Lumeo.Size.Sm => "py-8",
        Lumeo.Size.Lg => "py-16",
        _ => "py-12"
    };

    private string IconContainerClasses => $"flex {IconSizeClass} items-center justify-center rounded-[calc(var(--radius)*5)] {StatusBgClasses}";

    private string IconSizeClass => Size switch
    {
        Lumeo.Size.Sm => "h-12 w-12",
        Lumeo.Size.Lg => "h-20 w-20",
        _ => "h-16 w-16"
    };

    private string TitleClass => Size switch
    {
        Lumeo.Size.Sm => "mt-3 text-lg font-semibold text-foreground",
        Lumeo.Size.Lg => "mt-5 text-2xl font-semibold text-foreground",
        _ => "mt-4 text-xl font-semibold text-foreground"
    };

    private string SubTitleClass => Size switch
    {
        Lumeo.Size.Sm => "mt-1.5 text-xs text-muted-foreground",
        Lumeo.Size.Lg => "mt-2.5 text-base text-muted-foreground",
        _ => "mt-2 text-sm text-muted-foreground"
    };

    private string InnerIconClass => Size switch
    {
        Lumeo.Size.Sm => "h-6 w-6",
        Lumeo.Size.Lg => "h-10 w-10",
        _ => "h-8 w-8"
    };

    private string StatusBgClasses => Status switch
    {
        ResultStatus.Success => "bg-success-light text-success",
        ResultStatus.Error => "bg-destructive/10 text-destructive",
        ResultStatus.Warning => "bg-warning-light text-warning",
        ResultStatus.Info => "bg-primary/10 text-primary",
        ResultStatus.NotFound => "bg-muted text-muted-foreground",
        ResultStatus.Forbidden => "bg-destructive/10 text-destructive",
        ResultStatus.ServerError => "bg-destructive/10 text-destructive",
        _ => "bg-primary/10 text-primary"
    };

    // Decorative status glyph: aria-hidden so AT announces only the role="status"/
    // "alert" region text (Title/SubTitle), not a redundant icon label. (#wave3-53)
    private RenderFragment DefaultIcon => Status switch
    {
        ResultStatus.Success => @<SvgGlyph Svg="@(LumeoIcons.CircleCheck)" class="@InnerIconClass" aria-hidden="true" />,
        ResultStatus.Error => @<SvgGlyph Svg="@(LumeoIcons.CircleAlert)" class="@InnerIconClass" aria-hidden="true" />,
        ResultStatus.Warning => @<SvgGlyph Svg="@(LumeoIcons.TriangleAlert)" class="@InnerIconClass" aria-hidden="true" />,
        ResultStatus.Info => @<SvgGlyph Svg="@(LumeoIcons.Info)" class="@InnerIconClass" aria-hidden="true" />,
        ResultStatus.NotFound => @<SvgGlyph Svg="@(LumeoIcons.Search)" class="@InnerIconClass" aria-hidden="true" />,
        ResultStatus.Forbidden => @<SvgGlyph Svg="@(LumeoIcons.Lock)" class="@InnerIconClass" aria-hidden="true" />,
        ResultStatus.ServerError => @<SvgGlyph Svg="@(LumeoIcons.CircleAlert)" class="@InnerIconClass" aria-hidden="true" />,
        _ => @<SvgGlyph Svg="@(LumeoIcons.Info)" class="@InnerIconClass" aria-hidden="true" />
    };

    public enum ResultStatus { Success, Error, Warning, Info, NotFound, Forbidden, ServerError }
}
